svg.script:
let selectedId = null;
function clearSelection() {
  if (selectedId) {
    const el = document.getElementById(selectedId);
    if (el) el.classList.remove('selected');
  }
  selectedId = null;
}
function select(id) {
  clearSelection();
  const el = document.getElementById(id);
  if (el) { el.classList.add('selected'); selectedId = id; }
}
function sectionClicked(id) {
  select(id);
  // Placeholder hook: integrate with ScalaFX WebView bridge later.
  // window.app.sectionClicked(id) if you expose it, matching the earlier Scala code.
  if (window.app && typeof window.app.sectionClicked === 'function') {
    window.app.sectionClicked(id);
  }
}
